-- Seed the three hand-authored cases into the repository.

insert into public.cases (id, title, briefing, starting_focus, costs, suspects, evidence, timeline, solution, source)
values (
  'museum-diamond',
  'The Missing Diamond',
  'Tonight''s gala at the Aldermere Museum ended with the Vesper Star — a 40-carat blue diamond on loan for the season — gone from its case. Five people were on the premises when the lights flickered in the east wing. One of them is not who they say they are.',
  12,
  '{"unlockEvidence":2,"backgroundCheck":3,"wrongAccusation":3}'::jsonb,
  '[{"id":"grace_marlowe","name":"Grace Marlowe","role":"Museum Curator","persona":"Poised and precise, chooses her words like she''s citing a catalog entry. Protective of the museum''s reputation and quietly mortified by any suggestion she was careless. Formal, a little clipped when defensive, warms slightly when talking about the collection itself.","facts":{"timeline":[{"id":"gm_t1","text":"The gala opened at seven. I did a final walkthrough of the east wing myself just after seven-forty, everything was in order.","isLie":false},{"id":"gm_t2","text":"At nine-ten I went back to check on the case before closing remarks and found it empty. I sealed the wing and called security immediately.","isLie":false}],"motive":[{"id":"gm_m1","text":"The Vesper Star was on loan — if anything, its disappearance is a disaster for this museum''s insurance and our lending relationships for years to come. I have every reason to want it found, none to want it gone.","isLie":false},{"id":"gm_m2","text":"I fought hard to bring that piece here. I don''t lose things I fight for.","isLie":false}],"relationships":[{"id":"gm_r1","text":"I hired Dana Whitfield three weeks ago through a conservation placement agency. Strong references, remote interview — we''re short-staffed after the renovation, I didn''t have the luxury of being precious about it.","isLie":false},{"id":"gm_r2","text":"Marcus Foley has wanted that diamond in his own collection for years. I blocked his acquisition bid myself last spring. He hasn''t let me forget it.","isLie":false}],"alibi":[{"id":"gm_a1","text":"From about a quarter to nine until five past, I was in my office going over the insurance paperwork for the loan. Alone, unfortunately for how this looks.","isLie":false},{"id":"gm_a2","text":"There''s a hallway camera outside my office. If I''d left, it would show it.","isLie":false}],"evidenceReactions":[{"id":"gm_e_maintenance_log","evidenceId":"maintenance_log","text":"...I disabled sensor four myself at half past six, to get the new display mount installed without setting it off all evening. I meant to re-enable it. I should have logged it. That''s on me, not on anyone else.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Fifteen years with the museum, spotless record. One internal note: repeatedly cited for over-cautious insurance protocols on loaned pieces — if anything, she errs toward paranoid."},"initialLie":{"id":"gm_lie_sensors","text":"Every sensor in that corridor was live and working all night, I''d stake my job on it.","contradictedByEvidenceId":"maintenance_log"}},{"id":"owen_castell","name":"Owen Castell","role":"Head of Security","persona":"Gruff, clipped sentences, treats every question about his team''s performance as a personal attack. Proud of a clean record he''s about to have to complicate. Warms up only when talking about protocol and procedure in the abstract.","facts":{"timeline":[{"id":"oc_t1","text":"Routine sweep of the vault corridor logged clear at seven forty-two. Standard rotation, nothing flagged.","isLie":false},{"id":"oc_t2","text":"Vault alarm tripped silent at nine-oh-three — no audible alert, just a log entry. That''s normal for a case-weight sensor, it doesn''t scream the building down.","isLie":false}],"motive":[{"id":"oc_m1","text":"I''ve run this floor''s security for six years without an incident. Whatever happened tonight happened on my watch. That''s not a motive, that''s just going to be a bad quarter for me.","isLie":false}],"relationships":[{"id":"oc_r1","text":"I run background checks on every gala staffer and vendor myself, no exceptions. Dana Whitfield''s paperwork came back clean when I checked it three weeks ago.","isLie":false},{"id":"oc_r2","text":"Marcus Foley''s been on my radar for years, not for anything criminal — he just likes wandering into the wings he''s not supposed to be in. Museum charm, I call it.","isLie":false}],"alibi":[{"id":"oc_a1","text":"I was in the security office the whole time, eight-forty to nine-ten, eyes on the feeds.","isLie":false}],"evidenceReactions":[{"id":"oc_e_camera_outage","evidenceId":"camera_outage_report","text":"...Camera seven dropped for fourteen minutes during the power blip. Half the east wing flickered that night, I logged it as a building issue and moved on. I should have flagged the gap and had someone physically walk the corridor. That''s a mistake I''ll own.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Licensed, bonded, no red flags. One internal reprimand two years ago for a late shift-log filing — unrelated to tonight."},"initialLie":{"id":"oc_lie_feeds","text":"I had eyes on every camera feed personally, all night, zero blind spots. Nothing got past this office.","contradictedByEvidenceId":"camera_outage_report"}},{"id":"priya_nandan","name":"Priya Nandan","role":"Gala Patron & Board Donor","persona":"Warm and social on the surface, sharp underneath, used to being the most important person in any room she funds. Mentions her donations more than strictly necessary. Gets guarded, not hostile, when personal questions come up.","facts":{"timeline":[{"id":"pn_t1","text":"I was mingling most of the night — this gala only happens because people like me keep showing up and writing checks, so I make a point of being visible.","isLie":false}],"motive":[{"id":"pn_m1","text":"I''ve funded half the acquisitions budget for that wing over the last three years. I have absolutely no reason to want to see it robbed.","isLie":false}],"relationships":[{"id":"pn_r1","text":"Marcus Foley and I have gone head to head at auction more than once. It''s competitive, not personal — though he takes it a bit more personally than I do.","isLie":false},{"id":"pn_r2","text":"I don''t know the new conservator at all. Never met her before tonight, just saw her name on the gala program.","isLie":false}],"alibi":[{"id":"pn_a1","text":"I was near the string quartet basically all evening. Ask anyone, I was impossible to miss in this dress.","isLie":false}],"evidenceReactions":[{"id":"pn_e_coat_check","evidenceId":"coat_check_log","text":"...Fine. I stepped out to the coat check hallway for about ten minutes to take a phone call I didn''t want overheard. It was personal, a family matter, nothing to do with any of this. I''d rather not say more than that.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Donor and board records in order, verified annually by the museum''s own finance committee. Nothing irregular."},"initialLie":{"id":"pn_lie_floor","text":"I never once left the gala floor all night, I was right there the entire time.","contradictedByEvidenceId":"coat_check_log"}},{"id":"marcus_foley","name":"Marcus Foley","role":"Private Gem Collector","persona":"Smooth, name-drops his collection like small talk, tries to charm his way past uncomfortable questions with a joke. Underneath it, genuinely stung about losing the Vesper Star acquisition and doesn''t hide his opinions about the museum''s judgment.","facts":{"timeline":[{"id":"mf_t1","text":"I''ll admit I spent a good part of the evening near the east wing. Once you''ve seen that diamond up close, it''s hard to stay away.","isLie":false}],"motive":[{"id":"mf_m1","text":"I wanted that stone for my collection, everyone here knows it. Grace outbid me, fair and square, if you can call museum politics fair. I won''t pretend that didn''t sting.","isLie":false}],"relationships":[{"id":"mf_r1","text":"Priya Nandan and I have crossed paths at every major auction for a decade. She usually wins. I usually sulk about it for a week.","isLie":false},{"id":"mf_r2","text":"I don''t know the museum''s staff personally, I deal with the board, not the conservation department.","isLie":false}],"alibi":[{"id":"mf_a1","text":"I was talking with a group of other guests near the entrance from eight-thirty onward. Ask around, someone will remember.","isLie":true}],"evidenceReactions":[{"id":"mf_e_valet_log","evidenceId":"valet_log","text":"...Alright. I didn''t leave at eight-thirty. I was in the east corridor hoping for one more look at the case before it closed for the night. I know how that sounds. I didn''t touch anything, I just wanted to look.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"A civil dispute over a contested acquisition, filed three years ago by a rival collector, settled out of court. No criminal record."},"initialLie":{"id":"mf_lie_left","text":"I left the gala around eight-thirty, well before any of this happened. Ask the valet.","contradictedByEvidenceId":"valet_log"}},{"id":"dana_whitfield","name":"Dana Whitfield","role":"Junior Conservator","persona":"Quiet, competent, a little too eager to be helpful. Gives detailed, confident answers about conservation technique but goes vague and short whenever the conversation turns to her own history — not evasive exactly, just deflecting, like she''s redirecting a conversation she''s had to redirect before.","facts":{"timeline":[{"id":"dw_t1","text":"I''ve mostly been in the conservation lab this week, getting ready for the loan''s condition report. Tonight I was mostly keeping to myself, this isn''t really my crowd yet.","isLie":false}],"motive":[{"id":"dw_m1","text":"I just started three weeks ago, I''m still learning where everything is. I don''t think I''m anyone''s first thought for something like this.","isLie":false}],"relationships":[{"id":"dw_r1","text":"I did my interview and paperwork remotely — this is actually the first time I''ve met most of the staff in person.","isLie":false},{"id":"dw_r2","text":"I''d rather focus on the work than my resume, if it''s all the same to you.","isLie":false}],"alibi":[{"id":"dw_a1","text":"I told myself I''d finish a condition report tonight instead of mingling, so I was in the lab, on and off, for most of the evening.","isLie":true}],"evidenceReactions":[{"id":"dw_e_keycard_log","evidenceId":"keycard_log","text":"...That''s my badge, yes. I stepped into the corridor for a minute, I thought I heard something odd near the case and wanted to check it wasn''t a display fault. I didn''t see anything.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"No professional registry lists a conservator named Dana Whitfield matching this employment history prior to three weeks ago. The prior workplaces listed on the original hiring paperwork could not be independently verified."},"initialLie":{"id":"dw_lie_lab","text":"I was in the conservation lab the whole window between eight-forty and nine-ten, finishing a report.","contradictedByEvidenceId":"keycard_log"}}]'::jsonb,
  '[{"id":"maintenance_log","suspectId":"grace_marlowe","label":"Facilities maintenance log","description":"Sensor four on the east vault corridor was manually disabled at 6:30 PM for a display mount installation and was never re-enabled before the gala''s end.","unlockCost":2},{"id":"camera_outage_report","suspectId":"owen_castell","label":"Security camera outage report","description":"Corridor camera seven went dark for fourteen minutes, from 8:50 to 9:04 PM, coinciding with a reported power fluctuation in the east wing.","unlockCost":2},{"id":"coat_check_log","suspectId":"priya_nandan","label":"Coat check hallway log","description":"A guest matching Priya Nandan''s description was seen in the coat check hallway, away from the main gala floor, between 8:52 and 9:02 PM.","unlockCost":2},{"id":"valet_log","suspectId":"marcus_foley","label":"Valet retrieval log","description":"Marcus Foley''s car was not retrieved from valet until 9:20 PM, well after he claimed to have already left the gala.","unlockCost":2},{"id":"keycard_log","suspectId":"dana_whitfield","label":"Keycard access log","description":"A staff keycard badge registered entry to the east vault corridor door at 8:51 PM, during the exact window the corridor camera was dark.","unlockCost":2}]'::jsonb,
  '[{"time":"7:00 PM","type":"confirmed","text":"The gala opens; guests begin arriving in the main hall."},{"time":"7:42 PM","type":"confirmed","text":"Routine security sweep of the east vault corridor logged clear."},{"time":"8:15 PM","type":"confirmed","text":"The Vesper Star is confirmed in its case during a guard rotation check."},{"time":"8:45 PM","type":"claimed","suspectId":"grace_marlowe","text":"Grace Marlowe says she was reviewing insurance paperwork in her office."},{"time":"8:30 PM","type":"claimed","suspectId":"marcus_foley","text":"Marcus Foley says he had already left the gala by this point."},{"time":"8:40 PM","type":"claimed","suspectId":"dana_whitfield","text":"Dana Whitfield says she was in the conservation lab finishing a report."},{"time":"8:40 PM","type":"claimed","suspectId":"owen_castell","text":"Owen Castell says he was personally watching every camera feed, no gaps."},{"time":"8:50 PM","type":"confirmed","text":"A brief power fluctuation is reported in the east wing; corridor camera seven goes dark."},{"time":"8:51 PM","type":"confirmed","text":"A staff keycard badge registers entry to the east vault corridor door."},{"time":"8:52 PM","type":"claimed","suspectId":"priya_nandan","text":"Priya Nandan says she never left the main gala floor all night."},{"time":"9:03 PM","type":"confirmed","text":"The vault''s case-weight alarm trips silently — no audible alert."},{"time":"9:10 PM","type":"confirmed","text":"Grace Marlowe''s final walkthrough finds the case empty; the wing is sealed."}]'::jsonb,
  '{"culpritId":"dana_whitfield","narrative":"\"Dana Whitfield\" is not the name on any real conservator''s degree. The woman behind it is Elena Voss, a former assistant curator at the Aldermere who was quietly fired and blacklisted three years ago after being framed for a minor theft she didn''t commit — a case that was never solved and a name that never got cleared. When Grace''s understaffed department posted a remote conservation opening, Elena saw a way back in: a stolen identity good enough to survive a standard background check, but not a real one.\n\nOnce inside, she spent three weeks learning the building and quietly building a convincing replica of the Vesper Star in the conservation lab, under cover of her actual, legitimate conservation work. The gala night gave her a real target of opportunity: Grace''s unlogged, disabled sensor on the east corridor and a building-wide power flicker that took camera seven down for fourteen minutes were lucky breaks, not her doing — but she recognized the gap the instant it opened. At 8:51 PM she used her own legitimate staff badge to slip into the corridor, swapped the Vesper Star for the replica she''d built, and was back in the lab well before anyone thought to look for her.\n\nIt wasn''t a heist crew or a smash-and-grab. It was patience, a fake résumé good enough to pass a first glance, and someone the room had already decided to stop watching."}'::jsonb,
  'authored'
)
on conflict (id) do nothing;

insert into public.cases (id, title, briefing, starting_focus, costs, suspects, evidence, timeline, solution, source)
values (
  'flight-914-poisoning',
  'Turbulence at 30,000 Feet',
  'Three hours into a transcontinental flight, tech founder Elliot Pryce collapsed after a sip of his in-flight drink -- poisoned, and now recovering in a hospital on the ground below. The captain diverted, the cabin was sealed, and five people in business class are the only ones who could have reached his glass.',
  12,
  '{"unlockEvidence":2,"backgroundCheck":3,"wrongAccusation":3}'::jsonb,
  '[{"id":"priya_sethi","name":"Priya Sethi","role":"Business Consultant","persona":"Brisk and efficient, mildly impatient about the disruption to her schedule. Warms up noticeably when the conversation turns to her actual work.","facts":{"timeline":[{"id":"ps_t1","text":"I boarded with everyone else, took my seat in 2B, and spent most of the flight finishing a deck on my laptop.","isLie":false}],"motive":[{"id":"ps_m1","text":"I''d never even heard of Elliot Pryce before a flight attendant pointed him out after the fact. I have no history with the man at all.","isLie":false}],"relationships":[{"id":"ps_r1","text":"I exchanged maybe ten words with him the entire flight, mostly complaints about the wifi.","isLie":false}],"alibi":[{"id":"ps_a1","text":"I was at my seat working right up until the commotion started. The woman across the aisle was awake too, she can probably confirm that.","isLie":false}],"evidenceReactions":[{"id":"ps_e_cabin_service","evidenceId":"cabin_service_log","text":"...I did step into the galley once, to ask for more coffee. I was there maybe thirty seconds. I never went anywhere near his row.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Clean record. Verified consulting employment, no documented connection to Pryce or his company."},"initialLie":{"id":"ps_lie_seat","text":"I was in my seat with my laptop the entire flight, I never once got up.","contradictedByEvidenceId":"cabin_service_log"}},{"id":"marcus_yeun","name":"Marcus Yeun","role":"Flight Attendant","persona":"Professional and clipped, protective of cabin procedure, visibly anxious about liability and his certification.","facts":{"timeline":[{"id":"my_t1","text":"Drink service ran normally through business class between the first and second hour. Nothing unusual until Mr. Pryce''s collapse.","isLie":false}],"motive":[{"id":"my_m1","text":"I don''t have any stake in this beyond keeping my cabin safe. An incident like this is a nightmare for my certification, not something I''d invite.","isLie":false}],"relationships":[{"id":"my_r1","text":"I served him his drink the same as anyone else in that cabin. No relationship beyond that.","isLie":false}],"alibi":[{"id":"my_a1","text":"I was working the cabin for the entire flight, same as any other shift.","isLie":false}],"evidenceReactions":[{"id":"my_e_handoff","evidenceId":"crew_handoff_log","text":"...I stepped away for about two minutes to help a colleague with a passenger in economy. The cart was unattended in the aisle for that window. I should have locked it down first. That''s on me.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Eight years of service, clean record, certification current."},"initialLie":{"id":"my_lie_cart","text":"I personally poured and served every drink in that cabin myself, the cart was never out of my sight.","contradictedByEvidenceId":"crew_handoff_log"}},{"id":"diane_cho","name":"Diane Cho","role":"Retired Professor","persona":"Sharp and observant, a little imperious, clearly enjoys being the one who notices things -- but guarded about her own reasons for traveling.","facts":{"timeline":[{"id":"dc_t1","text":"I was seated across the aisle from Mr. Pryce, in 2D. Quiet flight, right up until the commotion.","isLie":false}],"motive":[{"id":"dc_m1","text":"I''d never laid eyes on the man before this flight. Whatever happened to him is none of my doing.","isLie":false}],"relationships":[{"id":"dc_r1","text":"We exchanged pleasantries when he sat down. Nothing more than that.","isLie":false}],"alibi":[{"id":"dc_a1","text":"I dozed on and off for most of the flight. It was a long one.","isLie":false}],"evidenceReactions":[{"id":"dc_e_call_button","evidenceId":"call_button_log","text":"...Alright, I woke up once to ask for a blanket. I was awake for a few minutes around then. I didn''t see anything unusual, or I''d have said so already.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"No criminal history. One unrelated note: barred from this airline''s lounge network three years ago after a dispute over a seating upgrade."},"initialLie":{"id":"dc_lie_asleep","text":"I was asleep for the entire flight, I didn''t see or hear a thing.","contradictedByEvidenceId":"call_button_log"}},{"id":"felix_adeyemi","name":"Felix Adeyemi","role":"Startup Founder","persona":"Energetic and a little combative, quick to justify himself, clearly still bitter about a public dispute he''d rather not relitigate.","facts":{"timeline":[{"id":"fa_t1","text":"I was seated a few rows back in 4A, nowhere near him for most of the flight.","isLie":false}],"motive":[{"id":"fa_m1","text":"Fine, yes, Elliot and I have history. He copied a feature from my product and out-marketed me for it. I''ve said plenty about that publicly, but I didn''t put anything in his drink.","isLie":false}],"relationships":[{"id":"fa_r1","text":"We''ve clashed online for over a year. I genuinely didn''t expect to be on the same flight as him.","isLie":false}],"alibi":[{"id":"fa_a1","text":"I stayed in my seat except to use the bathroom once, well before he collapsed.","isLie":false}],"evidenceReactions":[{"id":"fa_e_gate_note","evidenceId":"gate_agent_note","text":"...We had words at the gate, yes. He made a comment, I made one back. It was ugly for about thirty seconds, and then we both got on the plane and sat as far apart as business class allows.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"No criminal record. Public dispute with Pryce''s company is well documented, including a cease-and-desist exchange last year."},"initialLie":{"id":"fa_lie_noContact","text":"I hadn''t spoken to Elliot at all today, we didn''t even acknowledge each other.","contradictedByEvidenceId":"gate_agent_note"}},{"id":"renee_castillo","name":"Renee Castillo","role":"Marketing Director","persona":"Composed and pleasant, gives short, slightly rehearsed-sounding answers. Becomes noticeably more careful and clipped whenever the conversation drifts toward Elliot Pryce specifically.","facts":{"timeline":[{"id":"rc_t1","text":"I was seated in 2A, by the window. I kept to myself with a book for most of the flight.","isLie":false}],"motive":[{"id":"rc_m1","text":"I have a career and a family that have nothing to do with whatever industry drama Mr. Pryce is tangled up in. I''m honestly not sure why you''d look at me.","isLie":false}],"relationships":[{"id":"rc_r1","text":"I didn''t know him. I recognized his name from the news, same as anyone would.","isLie":false}],"alibi":[{"id":"rc_a1","text":"I didn''t leave my seat except once, early on, before drink service even started.","isLie":false}],"evidenceReactions":[{"id":"rc_e_loyalty","evidenceId":"loyalty_program_log","text":"...That account is old. I used my maiden name for years before I got married. Elliot and I crossed paths a long time ago, in a different life. I didn''t think it was relevant to mention.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"Frequent-flyer account originally registered years ago under the name Renee Ashford, with a professional background in pharmaceutical chemistry. Several historical itineraries overlap with Elliot Pryce''s during that period."},"initialLie":{"id":"rc_lie_neverMet","text":"I''d never met Elliot Pryce before today, I only know him from the headlines like everyone else.","contradictedByEvidenceId":"loyalty_program_log"}}]'::jsonb,
  '[{"id":"cabin_service_log","suspectId":"priya_sethi","label":"Galley service log","description":"The galley log shows Priya Sethi briefly entered the galley near the drink cart for under a minute, requesting coffee.","unlockCost":2},{"id":"crew_handoff_log","suspectId":"marcus_yeun","label":"Crew handoff log","description":"Marcus Yeun briefly left the cabin to assist another crew member, leaving the drink cart unattended in the aisle for roughly two minutes.","unlockCost":2},{"id":"call_button_log","suspectId":"diane_cho","label":"Call button log","description":"Diane Cho''s call button was used once mid-flight, requesting a blanket, during the window she claimed to have been fully asleep.","unlockCost":2},{"id":"gate_agent_note","suspectId":"felix_adeyemi","label":"Gate agent''s note","description":"A gate agent documented a brief but heated exchange between Felix Adeyemi and Elliot Pryce during boarding.","unlockCost":2},{"id":"loyalty_program_log","suspectId":"renee_castillo","label":"Frequent-flyer account history","description":"Renee Castillo''s frequent-flyer account was originally registered years ago under the name Renee Ashford, with several historical itineraries overlapping Elliot Pryce''s during that period.","unlockCost":2}]'::jsonb,
  '[{"time":"9:50 AM","type":"confirmed","text":"Boarding begins; a gate agent notes a brief, tense exchange near the jet bridge."},{"time":"10:15 AM","type":"confirmed","text":"Flight 914 departs on schedule."},{"time":"10:40 AM","type":"confirmed","text":"Elliot Pryce is served his drink during the first cabin service pass."},{"time":"10:45 AM","type":"claimed","suspectId":"priya_sethi","text":"Priya Sethi says she never left her seat the entire flight."},{"time":"10:50 AM","type":"claimed","suspectId":"marcus_yeun","text":"Marcus Yeun says he personally served every drink and never left the cart unattended."},{"time":"11:05 AM","type":"claimed","suspectId":"diane_cho","text":"Diane Cho says she was asleep for most of the flight."},{"time":"11:10 AM","type":"claimed","suspectId":"felix_adeyemi","text":"Felix Adeyemi says he hadn''t spoken to Elliot Pryce at all that day."},{"time":"11:15 AM","type":"claimed","suspectId":"renee_castillo","text":"Renee Castillo says she''d never met Elliot Pryce before today."},{"time":"11:20 AM","type":"confirmed","text":"Elliot Pryce complains of dizziness and collapses in his seat."},{"time":"11:25 AM","type":"confirmed","text":"The crew requests medical volunteers and the captain begins preparations to divert."},{"time":"11:40 AM","type":"confirmed","text":"Flight 914 diverts and lands; paramedics take Elliot Pryce to a hospital, stable but seriously ill."}]'::jsonb,
  '{"culpritId":"renee_castillo","narrative":"Renee Castillo did know Elliot Pryce -- intimately, once. Years ago, as Renee Ashford, she co-founded Elliot''s first company with him, both professionally and personally engaged to be married. When the company found real traction, Elliot maneuvered her out of the business in a boardroom vote she never saw coming, rewriting the founding story to erase her contribution entirely -- and the engagement collapsed in the same season, for the same reasons. Renee rebuilt quietly under her married name, retrained as a pharmaceutical chemist, and never stopped tracking his career from a distance.\n\nBooking herself onto his flight was not a coincidence. Seated one row behind him in business class, she watched the cabin service pass and waited for a moment the aisle was clear -- Marcus''s brief absence from the cart gave her exactly the gap she needed. Using a compound from her professional background, easy for her to obtain and easy to dose without a trace of flavor, she altered his drink during that short window and returned to her seat with a book, precisely as she''d described to everyone who asked.\n\nIt wasn''t rage or a public scene. It was years of quiet planning, a stolen professional skill turned into a weapon, and a name change that meant nobody on that plane thought to ask the one question that mattered: had she ever met him before?"}'::jsonb,
  'authored'
)
on conflict (id) do nothing;

insert into public.cases (id, title, briefing, starting_focus, costs, suspects, evidence, timeline, solution, source)
values (
  'meridian-station-sabotage',
  'Oxygen Loss at Meridian Station',
  'At 03:00 station time, the oxygen scrubber in Module C failed without warning, tripping an emergency alarm across the Meridian Mars outpost. No one was hurt -- the crew reached the safe module in time -- but the timing is strange: an Earth Oversight Council audit team is due to arrive within the week.',
  12,
  '{"unlockEvidence":2,"backgroundCheck":3,"wrongAccusation":3}'::jsonb,
  '[{"id":"aiko_reyes","name":"Aiko Reyes","role":"Station Commander","persona":"Composed and protocol-driven, carries the weight of crew safety visibly. Answers precisely, like she''s already anticipating an inquiry board.","facts":{"timeline":[{"id":"ar_t1","text":"I initiated the emergency lockdown the moment the alarm tripped and had everyone into the safe module within four minutes.","isLie":false}],"motive":[{"id":"ar_m1","text":"I have nothing to gain from an equipment failure. An incident like this triggers a full inquiry that could end my command.","isLie":false}],"relationships":[{"id":"ar_r1","text":"I approved Dr. Voss''s data archive access requests the same as anyone else''s, routine sign-offs. Nothing about them stood out to me.","isLie":false}],"alibi":[{"id":"ar_a1","text":"I was in the command module the entire time, running the response.","isLie":false}],"evidenceReactions":[{"id":"ar_e_maintenance","evidenceId":"maintenance_override_log","text":"...I deferred that safety round this week and meant to hand it to Dmitri directly. The message never went through properly. That''s on me, not him.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Command record spotless. Twelve years of service without a prior incident."},"initialLie":{"id":"ar_lie_scrubber","text":"I personally verified the Module C scrubber system during this week''s safety rounds, it was in good working order.","contradictedByEvidenceId":"maintenance_override_log"}},{"id":"dmitri_kessler","name":"Dmitri Kessler","role":"Systems Engineer","persona":"Technical and gruff, proud of the station''s redundant systems, visibly defensive whenever equipment reliability comes into question.","facts":{"timeline":[{"id":"dk_t1","text":"The scrubber malfunction tripped at oh-three-hundred. I had the backup system online within ninety seconds.","isLie":false}],"motive":[{"id":"dk_m1","text":"This station''s systems are my responsibility and my reputation. A failure like this makes me look bad, it doesn''t help me.","isLie":false}],"relationships":[{"id":"dk_r1","text":"I work with everyone on this crew daily. Nothing between me and Dr. Voss beyond routine equipment requests.","isLie":false}],"alibi":[{"id":"dk_a1","text":"I was asleep in my quarters until the alarm woke me, same as most of the crew.","isLie":false}],"evidenceReactions":[{"id":"dk_e_diagnostic","evidenceId":"diagnostic_log","text":"...There was an amber flag on the backup sensor, yes. It was low priority, queued behind higher-severity tickets. In hindsight I should have escalated it.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Certified engineer, six years on-station, no disciplinary record."},"initialLie":{"id":"dk_lie_diagnostic","text":"I ran a full diagnostic on every life support system just two days ago, everything was flagged green across the board.","contradictedByEvidenceId":"diagnostic_log"}},{"id":"sofia_lindqvist","name":"Sofia Lindqvist","role":"Medical Officer","persona":"Calm under pressure, clinical in her phrasing, notices physiological and behavioral details others miss.","facts":{"timeline":[{"id":"sl_t1","text":"I treated two crew members for minor smoke inhalation afterward. Nothing life-threatening.","isLie":false}],"motive":[{"id":"sl_m1","text":"My job is keeping this crew alive. An oxygen incident is the last thing I''d want.","isLie":false}],"relationships":[{"id":"sl_r1","text":"I see everyone professionally at some point, physicals, checkups. Nothing outside of that with Dr. Voss specifically.","isLie":false}],"alibi":[{"id":"sl_a1","text":"I was in the medical bay finishing charting when the alarm went off.","isLie":false}],"evidenceReactions":[{"id":"sl_e_medbay","evidenceId":"medbay_log","text":"...Fine, I stepped into the bunk next door for about forty minutes. It''s permitted during a quiet shift. I just didn''t think it was relevant to mention.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"Licensed and current. No irregularities in her service record."},"initialLie":{"id":"sl_lie_awake","text":"I was awake and alert in the med bay the entire night, I don''t miss things on my shift.","contradictedByEvidenceId":"medbay_log"}},{"id":"jonas_okafor","name":"Jonas Okafor","role":"Communications Officer","persona":"Chatty and restless, openly counting down the days until rotation home, a little too eager to speculate about what happened.","facts":{"timeline":[{"id":"jo_t1","text":"I was pulling a late shift monitoring the Earth-relay window when the alarm tripped.","isLie":false}],"motive":[{"id":"jo_m1","text":"I''ve got four months left on this rotation and every reason to want a quiet, uneventful tour. This is the opposite of what I want.","isLie":false}],"relationships":[{"id":"jo_r1","text":"I talk to everyone on this crew, it''s the job. Nothing specific with Dr. Voss beyond routine chatter.","isLie":false}],"alibi":[{"id":"jo_a1","text":"I was at the comms station the whole time. The relay logs are timestamped to the second, you can check.","isLie":false}],"evidenceReactions":[{"id":"jo_e_corridor","evidenceId":"corridor_access_log","text":"...Okay, I did step out for about five minutes to grab a ration pack near Module C. It''s a two-minute walk from comms. I didn''t think it needed mentioning.","isLie":false}]},"backgroundCheck":{"flagged":false,"text":"No irregularities. Standard performance reviews, on track for rotation home."},"initialLie":{"id":"jo_lie_neverLeft","text":"I hadn''t left the comms station for even a minute all shift.","contradictedByEvidenceId":"corridor_access_log"}},{"id":"petra_voss","name":"Petra Voss","role":"Lead Researcher","persona":"Precise and controlled, gives measured, professional answers -- and grows noticeably more clipped and defensive the closer the conversation gets to her research timeline or data.","facts":{"timeline":[{"id":"pv_t1","text":"I was finalizing data backups ahead of the audit team''s arrival next week. That''s normal pre-audit preparation.","isLie":false}],"motive":[{"id":"pv_m1","text":"The station''s funding depends on this research program showing results. Everyone here has a stake in it succeeding, not just me.","isLie":false}],"relationships":[{"id":"pv_r1","text":"I coordinate with the whole crew on data logistics. Nothing outside of the professional.","isLie":false}],"alibi":[{"id":"pv_a1","text":"I was alone in the archive room finishing backups when the alarm went off. I made it to the safe module with everyone else.","isLie":false}],"evidenceReactions":[{"id":"pv_e_override","evidenceId":"environmental_override_log","text":"...I did access that terminal, briefly. I was checking humidity levels for a sample storage concern, nothing to do with the scrubber itself. The timing is a coincidence.","isLie":false}]},"backgroundCheck":{"flagged":true,"text":"Data revision log flagged: multiple research datasets show late-cycle edits inconsistent with original sample timestamps, submitted in the weeks immediately preceding a scheduled research audit."},"initialLie":{"id":"pv_lie_neverTouched","text":"I never touched the environmental controls, that''s not part of my role at all.","contradictedByEvidenceId":"environmental_override_log"}}]'::jsonb,
  '[{"id":"maintenance_override_log","suspectId":"aiko_reyes","label":"Maintenance scheduling log","description":"This week''s Module C safety round was deferred by Commander Reyes and handed off verbally to the engineering team, but the handoff was never logged or confirmed.","unlockCost":2},{"id":"diagnostic_log","suspectId":"dmitri_kessler","label":"Systems diagnostic log","description":"A diagnostic run two days prior flagged Module C''s backup scrubber redundancy sensor amber -- a low-priority warning queued for follow-up that had not yet occurred.","unlockCost":2},{"id":"medbay_log","suspectId":"sofia_lindqvist","label":"Medical bay shift log","description":"The medical bay''s occupancy log shows Dr. Lindqvist logged roughly forty minutes resting in the adjoining bunk during the night shift, ending shortly before the alarm.","unlockCost":2},{"id":"corridor_access_log","suspectId":"jonas_okafor","label":"Corridor badge access log","description":"A badge scan shows Jonas Okafor briefly left the comms station and accessed the corridor near Module C roughly twenty minutes before the incident.","unlockCost":2},{"id":"environmental_override_log","suspectId":"petra_voss","label":"Environmental control terminal log","description":"The archive wing''s environmental control terminal logged a manual override command sent to the Module C scrubber system at 02:58, ninety seconds before the malfunction alarm tripped.","unlockCost":2}]'::jsonb,
  '[{"time":"2:40 AM","type":"confirmed","text":"Night shift begins; most of the crew retires to quarters except scheduled watch personnel."},{"time":"2:50 AM","type":"claimed","suspectId":"petra_voss","text":"Petra Voss says she was in the archive room finalizing pre-audit data backups."},{"time":"2:58 AM","type":"confirmed","text":"The archive wing''s environmental control terminal logs a manual override command sent to the Module C scrubber system."},{"time":"3:00 AM","type":"confirmed","text":"The Module C oxygen scrubber malfunctions; an emergency alarm trips station-wide."},{"time":"3:01 AM","type":"claimed","suspectId":"aiko_reyes","text":"Aiko Reyes says she initiated the emergency lockdown within moments of the alarm."},{"time":"3:02 AM","type":"claimed","suspectId":"dmitri_kessler","text":"Dmitri Kessler says he had the backup life-support system online within ninety seconds."},{"time":"3:04 AM","type":"confirmed","text":"All crew are accounted for and sealed in the station''s safe module within four minutes of the alarm."},{"time":"3:05 AM","type":"claimed","suspectId":"sofia_lindqvist","text":"Sofia Lindqvist says she was awake and alert in the med bay the entire night."},{"time":"3:06 AM","type":"claimed","suspectId":"jonas_okafor","text":"Jonas Okafor says he hadn''t left the comms station for even a minute all shift."},{"time":"3:20 AM","type":"confirmed","text":"Backup scrubbers stabilize oxygen levels; the immediate emergency passes without injury."}]'::jsonb,
  '{"culpritId":"petra_voss","narrative":"The oxygen scrubber malfunction in Module C was not an accident. Dr. Petra Voss engineered it deliberately, using her terminal access to the environmental control systems to trigger a controlled, survivable failure -- close enough to force an emergency response, but never actually life-threatening, since she made sure everyone would reach the safe module in time.\n\nHer real problem wasn''t the station''s air. It was the Earth Oversight Council''s surprise research audit, scheduled to arrive within the week. Months of atmospheric and soil sample data she''d submitted under funding pressure had been quietly backfilled and adjusted to match deadlines she''d missed in the field -- fabrications an experienced auditor would catch in an afternoon. An emergency serious enough to justify wiping the archive''s physical backups \"for safety\" would destroy the evidence before anyone thought to look for it.\n\nShe was in the archive room exactly when she said she was, doing exactly what she said she was doing -- backups. She simply didn''t mention that the emergency she was backing up from was one she''d caused herself, ninety seconds earlier, from the same terminal."}'::jsonb,
  'authored'
)
on conflict (id) do nothing;

